<?php
declare(strict_types=1);
namespace Ostoya\ShoppingList\Model\Resolver; use Magento\Framework\GraphQl\Config\Element\Field;use Magento\Framework\GraphQl\Query\ResolverInterface;use Magento\Framework\GraphQl\Schema\Type\ResolveInfo;use Ostoya\ShoppingList\Model\Service\ShoppingListService;
class RenameShoppingList implements ResolverInterface{public function __construct(private readonly CustomerContext $customerContext,private readonly ShoppingListService $service,private readonly ResolverDataFormatter $formatter){} public function resolve(Field $field,$context,ResolveInfo $info,array $value=null,array $args=null): array{$input=$args['input'];$list=$this->service->renameList($this->customerContext->getCustomerId($context),(int)$input['list_id'],(string)$input['list_name']);return ['success'=>true,'message'=>'Shopping list updated.','list'=>$this->formatter->formatList($list,[])];}}
